import{_ as t,o as e,c as a,a9 as n}from"./chunks/framework.D4xYp1Zt.js";const o="/images/19-things-learned-nigeria/Nigeria-Map1-1024x730.png",p="/images/19-things-learned-nigeria/Population-Graph1-1024x864.png",i="/images/19-things-learned-nigeria/Nigeria-on-US.jpg",s="/images/19-things-learned-nigeria/Nigeria-History1-910x1024.png",g="/images/19-things-learned-nigeria/IMG_4585-1024x768.jpg",h="/images/19-things-learned-nigeria/IMG_46281-768x1024.jpg",l="/images/19-things-learned-nigeria/IMG_4621-1024x724.jpg",m="/images/19-things-learned-nigeria/IMG_4829-1024x677.jpg",c="/images/19-things-learned-nigeria/IMG_4793-974x1024.jpg",_="/images/19-things-learned-nigeria/Yahoos-1024x459.jpg",w="/images/19-things-learned-nigeria/IMG_4698-1024x768.jpg",u="/images/19-things-learned-nigeria/IMG_4754-1024x578.jpg",f="/images/19-things-learned-nigeria/IMG_4738-1024x786.jpg",b="/images/19-things-learned-nigeria/IMG_4727-1024x646.jpg",d="/images/19-things-learned-nigeria/IMG_4709-1024x737.jpg",k="/images/19-things-learned-nigeria/IMG_4684-1024x791.jpg",y="/images/19-things-learned-nigeria/IMG_4700-1024x571.jpg",I="/images/19-things-learned-nigeria/pinit_fg_en_rect_gray_20.png",Y=JSON.parse('{"title":"19 Things I Learned in Nigeria","description":"","frontmatter":{"title":"19 Things I Learned in Nigeria","titleZh":"我在尼日利亚学到的19件事","date":"2014-08-13T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/08/19-things-learned-nigeria.html","slug":"19-things-learned-nigeria"},"headers":[],"relativePath":"posts/19-things-learned-nigeria.md","filePath":"posts/19-things-learned-nigeria.md","lastUpdated":1782886257000}'),G={name:"posts/19-things-learned-nigeria.md"};function M(j,r,x,N,q,F){return e(),a("div",null,[...r[0]||(r[0]=[n('<h1 id="我在尼日利亚学到的19件事-·-19-things-i-learned-in-nigeria" tabindex="-1">我在尼日利亚学到的19件事 · 19 Things I Learned in Nigeria <a class="header-anchor" href="#我在尼日利亚学到的19件事-·-19-things-i-learned-in-nigeria" aria-label="Permalink to &quot;我在尼日利亚学到的19件事 · 19 Things I Learned in Nigeria&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/08/19-things-learned-nigeria.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/08/19-things-learned-nigeria.html</a> · 2014-08-13</p></blockquote><p>如果你不知道《怪地方里的怪事》是什么、我为什么一个人跑到尼日利亚,<a href="https://waitbutwhy.com/2014/07/odd-things-odd-places-intro.html" target="_blank" rel="noreferrer">这里有解释</a>。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/Nigeria-Map1.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt="Nigeria Map"></a></p><p>再没有比这更让人错乱的旅行体验了——花两周时间习惯了日本,然后直接飞去尼日利亚。这两个地方在几乎所有可以对立的维度上都是对立的。就连我在东京机场托运行李时,那个女的看到我要去哪儿,那眼神就像在说:「你到底哪儿有毛病?」</p><p>我不知道我哪儿有毛病。但显然我已经决定离开这个世界上最干净、最有秩序、最安全的地方,去往一个跟这三个形容词完全不沾边的地方,然后突然之间,我就站在非洲最大城市的正中央,努力不让自己死掉。</p><p>不过我们等会儿再回到我这边的情况——先来了解一下尼日利亚。</p><p><strong>关于尼日利亚</strong></p><p>(所有数据除非另有出处,均来自 <a href="https://www.cia.gov/library/publications/the-world-factbook/geos/ni.html" target="_blank" rel="noreferrer">CIA 世界概况</a>)</p><p><strong>人:</strong></p><p>尼日利亚有很多尼日利亚人。多到什么程度?哪怕你把他们中的一半从这个国家挪走,尼日利亚<strong>依然</strong>是非洲人口最多的国家(1.79 亿)。尼日利亚的人口比英国、法国、西班牙加起来还多,并且这个星球上每 7 个黑人里就有 1 个是尼日利亚人。</p><p>在国土面积、人口规模和人口密度上,尼日利亚跟巴基斯坦挺像;而尼日利亚的超级大都市拉各斯是世界第四大城市,人口和密度可以跟孟买、首尔、雅加达相提并论。</p><p>尼日利亚人口还非常年轻——中位数年龄 18.2 岁,也就是说一半尼日利亚人都是 17 岁及以下的孩子,这意味着如果哪天尼日利亚的孩子们受够了、决定单独成立一个国家,那将是非洲最大的国家,也是最烦人的国家。再加上世界最高的生育率之一(每名女性生育 5.25 个孩子),你就有了一个正在飞速膨胀的人口。目前尼日利亚在国家人口排行榜上排第 7,到 2050 年,<a href="http://esa.un.org/unpd/wpp/unpp/panel_population.htm" target="_blank" rel="noreferrer">预计</a>将有 4.4 亿人,一跃升到第 3 位,仅次于印度和中国:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/Population-Graph1.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt="Population Graph"></a></p><p>但情况没这么简单。这些人都是尼日利亚人,但其实他们分属 250 个不同的族群、说着 510 种不同的语言,外面被英国人画了一圈边界。这基本就是自找麻烦。</p><p>健康是一大难题——尼日利亚的婴儿死亡率世界排名第 10,预期寿命世界倒数第 12(52.6 岁),3.1% 的尼日利亚成年人感染 HIV/艾滋病。</p><p><strong>宗教与民族:</strong> 尼日利亚属于那种棘手的国家——大约一半人口是穆斯林,一半是基督徒,虽然大多数人对此都能和平共处,但宗教极端分子制造了大量暴力,把一切都搞砸了。再加上那 250 个民族,其中最大的三个占了总人口的 68%——北部的豪萨族 (Hausa)(多为穆斯林)、东南部的伊博族 (Igbo)(多为基督徒),以及西南部的约鲁巴族 (Yoruba)(穆斯林和基督徒都有)——这三大族群之间普遍的互看不顺眼,正是这个国家暴力历史和政治动荡的大部分原因。</p><p><strong>国土:</strong> 尼日利亚是世界第 32 大国(按陆地面积算),差不多是两个加州那么大。叠在美国上,它可以把纽约、芝加哥和亚特兰大全都囊括进去:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/Nigeria-on-US.jpg" target="_blank" rel="noreferrer"><img src="'+i+'" alt="Nigeria on US"></a></p><p><strong>经济:</strong> 名义 GDP 刚刚超过 5000 亿美元,尼日利亚拥有非洲最大的经济体,这主要归功于其庞大的石油储量——它是世界第 8 大原油出口国。但由于政府极度腐败,这些财富并没有给民众带来什么好处——基础设施一团糟,24% 的成年人失业,三分之二的尼日利亚人生活在极端贫困中。尼日利亚的<a href="http://www.gallup.com/poll/166211/worldwide-median-household-income-000.aspx#2" target="_blank" rel="noreferrer">人均收入中位数</a>是 493 美元,这意味着一个每周挣 10 美元的尼日利亚人已经位列全国财富的前半段。</p><p><strong>一张图看历史:</strong></p><p>今天被称为尼日利亚的这片土地,一万多年来一直是众多古文明的家园。到了 19 世纪末,英国人在欧洲各国争夺非洲势力范围的白热化时期,把自己的触角伸了进来。这片地区在 1901 年成为英国保护国,今天尼日利亚的国界则是 1914 年划定的。二战之后,尼日利亚人极度希望英国人滚蛋,英国终于在 1960 年撤离,并临走前给尼日利亚建立了一个新的代议制政府(如今是仿照美国体制的联邦总统制共和国)。</p><p>所以 1960 年既是尼日利亚独立的第一年,也是我只能称之为「尼日利亚政变嘉年华」的开始——一场为期 50 年、为争取稳定和民主而进行的毁灭性挣扎。</p><p>如果你真的很想深入了解「尼日利亚政变嘉年华」,<a href="https://www.youtube.com/watch?v=BPEd8xujG4Y" target="_blank" rel="noreferrer">这里</a>有一部制作精良的 2.5 小时纪录片,讲述现代尼日利亚的历史。对于只是稍微感兴趣的人,我花了自己人生四分之一(译注:此处 Tim 在夸张)的时间把要点整理成了下面这张图。而对尼日利亚历史几乎完全不感兴趣的人,只需要数一数时间线上那些大红色的政变圆点,就能理解:事情一直很糟糕。图片按蓝色数字顺序时间推进,你可以点击查看大图。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/Nigeria-History3.pdf" target="_blank" rel="noreferrer"><img src="'+s+'" alt="Nigeria History"></a></p><p><strong>成为 Adebayo 家的第 10 个兄弟姐妹</strong></p><p>在我们开始聊我在尼日利亚学到什么之前,先介绍一下我大部分东西是从谁那儿学来的——</p><p>了解一个陌生地方最好的办法就是认识当地人,我在尼日利亚运气不错。通过一个朋友,我联系上了一个 31 岁的尼日利亚人,名叫 Femi,他主动提出到机场接我。结果这一接就变成了 Femi 几乎在整个行程中都罩着我——带我在拉各斯 (Lagos) 转悠、请我去他公寓、让他的兄弟们把我送到他们童年老家跟他们妈妈一起住了半个星期、把我介绍给一堆当地人,还回答了我大约 12000 个关于尼日利亚生活的问题。真方便。</p><p>旅途中我住在这个家庭的不同成员那里,和其中几位还挺熟——这是一位妈妈和她的九个孩子,年龄从九岁<a href="#footnote-1-2244">1</a>到 32 岁不等。在一个小村子里长大之后,四个兄弟姐妹现在一起住在拉各斯一间小小的一居室公寓里,另外三个则在更小的城镇 Ife 和妈妈一起住在一个单间公寓里。这两套公寓都是 Femi 出钱租的,他是老二,是最大的儿子。他正准备上大学时,他们的爸爸病倒了,英年早逝。Femi 放弃了自己的计划,开始做职业司机养家,这份工作他一干就是十年,到现在还在做,他的兄弟姐妹们都说他就像所有人的爸爸一样。</p><p>而且因为这家人碰巧超级好客,我就厚脸皮地一屁股坐进去当了他们家第 10 个、也是最没用的兄弟姐妹,这让我对那里的生活有了远比平时深入得多的了解。以下是我一路学到的东西:</p><p><strong>我在那里学到的 19 件事</strong></p><p><strong>1)尼日利亚小孩喜欢在飞机上尽情释放自我。</strong></p><p>**2)两个人流利地说同一种语言,不代表他们就能轻松交流。**作为前英国殖民地,尼日利亚的官方国语是英语。但实际上,大多数人的第一语言是当地的尼日利亚语言,英语是他们的第二语言,通常很流利,但有时说起来没那么自在。而且许多受教育程度较低的尼日利亚人根本不会说英语。</p><p>Femi 和他的兄弟姐妹说一口流利的英语,但口音跟我的太不一样了,有时候他们说话时,我都分不清他们到底是在用尼日利亚语(约鲁巴语 (Yoruba))互相聊天,还是在跟我说英语,我就会一边小小地慌一下,一边努力搞清楚状况。</p><p><strong>3) 在尼日利亚,针对亚洲人的种族歧视是家常便饭。</strong> 在 Femi 的公寓里,我们打开电视,看到一对当红喜剧搭档正在台上表演。某一刻他们开始跟观众席里不同的人聊天,聊到一位亚洲女性时,他们把眼角往后一拉,喊了一句 &quot;ching chong ching!&quot;,观众爆笑。挺不一样的。</p><p><strong>4) 这个国家平均每天停电 10 次。</strong> 也就是说,光我这趟来访就赶上了 100 多次。头几次停电真的把我吓得不轻,我会来一句 &quot;<a href="https://www.youtube.com/watch?v=EF8GhC-T_Mo" target="_blank" rel="noreferrer">哦这可有意思了!</a>&quot;,然后才反应过来大惊小怪特别掉价——其他人的做法就是继续聊天,压根不搭理停电这回事。如果你运气好在酒店或餐厅,发电机几分钟内就能把电供上。但我在 Femi 家或他妈妈家的时候,电常常一停就是好几个小时。没人知道停电会持续多久——短则 30 秒,长则三天。</p><p>于是有好几次,我在一个屋子里跟六个人一起待了一整晚,吃饭聊天几个小时,全程都在黑暗中,谁也看不见谁的脸(这本来没什么,直到我想跟坐在旁边的一个两岁小孩玩玩,才发现她的手上黏糊糊全是不知道什么东西,而我又没法把手擦干净,只好继续用手吃饭——那儿的传统吃法就是用手抓)。</p><p>停电这事儿让大多数尼日利亚人恨得牙痒痒,他们觉得政府的钱多得完全够解决这个问题。</p><p>既然说到这儿,另一件让我遇到的人翻白眼翻到冒烟的基础设施烂摊子,就是高速公路的状况。从拉各斯 (Lagos) 开往附近的伊巴丹 (Ibadan) 时,一段 10 英里的路我们花了大约四个小时才通过,因为路上裂缝和坑洞太多,直接堵成了停车场。<a href="#footnote-2-2244">2</a> 有意思的是,尼日利亚人管一段大堵车叫 &quot;go-slow&quot;,而 go-slow 的一部分特色就是彻底无视法规,车子会做出各种疯狂动作——比如翻越中央隔离带,在对向来车之间蛇形穿梭,只为快点开过去。再给这场面加点料:据说警察有时候会趁着堵车走过来抢劫路人——所以有人叮嘱我把手机收好别露出来。我在 <a href="https://youtu.be/2D4kW6Odg1Q" target="_blank" rel="noreferrer">尼日利亚视频</a> 的 2:42 处放了几段 go-slow 的画面。</p><p><strong>5) 事实证明,在尼日利亚,白人非常显眼。</strong> 有一次坐车途中,我看到前面卡车上写着这么一行字:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/IMG_4585.jpg" target="_blank" rel="noreferrer"><img src="'+g+'" alt="Oyinbo"></a></p><p>又是那个词。Oyinbo。我一直以为这是一种俚语式的&quot;你好&quot;,因为我走在街上时人们不停地对我这么说。为了确认,我问了车里的人这是什么意思。他们笑了。&quot;意思是白人。&quot;</p><p>哎哟你瞧瞧。</p><p>我想了想,意识到自从几天前离开机场以来,我一个其他的白人都没见过。</p><p>而且我感觉到,我们所在的地方越偏远,人们见到我就越惊讶。在小镇或村庄里,当有人看见我走过,他们会看我一眼,然后转开视线,然后突然回头再看,睁大眼睛、咧嘴大笑,叫来身边其他人的注意,然后大家一起睁大眼睛、咧嘴大笑地看着我——为这难得一见的景象既高兴又觉得有趣。</p><p>我相信在有欧洲殖民历史的背景下,种族问题在尼日利亚和别处一样复杂,但就我自己的经历而言,我完全没有感受到任何负面情绪——只有格外的友好——包括这趟旅程中大约 2500 次有人喊我 oyinbo,从来都不带任何敌意。</p><p>(暂停一下,让有经验的撒哈拉以南非洲旅行者居高临下地拍拍我的头。)</p><p>另一件反复发生的有趣事情是,孩子们经常会研究我的手或胳膊,或者摸(或者拽)我的头发,Femi 的哥哥解释说这可能是因为他们之前从没近距离见过白人。这里有个例子——而且我也不知道为什么我的胳膊看起来像具尸体的胳膊,所以别问:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/IMG_46281.jpg" target="_blank" rel="noreferrer"><img src="'+h+'" alt="IMG4628"></a></p><p><strong>6) 我遇到的一个人告诉我他没有一个亲兄弟姐妹,但有 20 多个同父异母的兄弟姐妹,因为他父亲有七个老婆。</strong> 我就是需要告诉你一声。</p><p><strong>7) 尼日利亚不是当同性恋的好地方。</strong> 2014 年 1 月,乔纳森 (Jonathan) 总统签署了《同性婚姻禁止法》(Same Sex Marriage Prohibition Act),同性结婚可判 14 年监禁,&quot;其他违反此法的行为&quot;可判 10 年。而且如果你对朋友是同性恋一事保持沉默,可能会被判 5 年。这项法律一通过,警察就开始抓人了。</p><p><strong>8) 婴儿的胳膊也可以当把手用。</strong> 我不断看到人们抓着婴儿或幼儿的胳膊把他们提起来挪到新的位置。这似乎完全不会伤到或让孩子不舒服,既滑稽又实用。我将来跟小孩打交道都要采用这种做法。</p><p><strong>9) 很多人认为古德勒克·乔纳森 (Goodluck Jonathan) 总统很蠢,并指责他放任恐怖组织博科圣地 (Boko Haram) 肆虐。</strong> 博科圣地是一个激进的伊斯兰主义恐怖组织,过去五年里一直在尼日利亚北部烧杀掳掠,仅 2014 年就已经杀害了 2,000 多名平民。他们的名字奇怪地具体,意思是「西方教育是被禁止的」,目标是把尼日利亚变成一个强硬的伊斯兰国家,而他们的头目<a href="https://www.youtube.com/watch?v=sLAKoJYTLfA" target="_blank" rel="noreferrer">想杀掉</a>很多人。你大概还记得今年 4 月他们绑架了 200 多名女学生的新闻铺天盖地——然后媒体腻了,就跑去报道别的事情了。</p><p>至于这位总统,A) 我了解到 Goodluck 和 Jonathan 在尼日利亚分别是常见的名和姓,以及 B) 他是个林登·约翰逊 (Lyndon Johnson) ——也就是说他本来是副总统,总统去世后他接了班,后来又赢了选举,而我聊过的那些人都觉得原来那位总统在应对博科圣地上会做得好得多。</p><p>既然我们已经在基于我碰到的一小撮个人观点对尼日利亚下宏大结论了……</p><p><strong>10) 很多人认为尼日利亚的超级富豪们大多自私、贪婪,他们对维护现状和自己的精英地位的兴趣远大于改善国家未来,而这是灾难性的,因为他们对腐败政府的政策有着巨大的影响力。</strong> 是是是我知道,这也正是你们国家的问题——但我总觉得你们国家的腐败/不平等问题没有尼日利亚这么极端。</p><p><strong>11) 尼日利亚有一个高产的电影产业叫瑙莱坞 (Nollywood)。</strong> 瑙莱坞每<em>周</em>出产 200 部电影,产量超过好莱坞,仅次于宝莱坞。</p><p><strong>12) 教育在尼日利亚备受尊崇。</strong> 尊崇教育是个相当普遍的概念,但在尼日利亚尤其被看重。一个证据是 2006 年美国人口普查<a href="http://www.chron.com/news/article/Data-show-Nigerians-the-most-educated-in-the-U-S-1600808.php" target="_blank" rel="noreferrer">发现</a>,生活在美国的尼日利亚人是「全国受教育程度最高的族裔或种族群体」,其中 17% 拥有硕士或以上学位。</p><p><strong>13) 左手是禁忌。</strong> 鉴于我之前在中东和亚洲已经好几次遇到过这个完全一样的禁忌,你可能觉得我早该记住了,但我至少犯了五次错,比如用左手碰食物、用左手把东西递给别人,每次都被训一顿。当地人的逻辑是,左手是用来干所有脏活的,右手要保持干净,用于讲究清洁的事。而在一个连肥皂都没有的乡村地区待了四天之后,我明白了这可不是随便定的——这是一项重要的卫生习惯。</p><p>但是——</p><p><strong>14) 男人和男性朋友手牵手不是禁忌。</strong> 作为美国那套禁忌体系培养出来的产物,当我和 Femi 并排走路、他突然牵起我的手时,我整个人都愣了。而且我说的不是那种比较温和的连指手套式握法——是完整的十指相扣式。以我的经验,连指手套式主要是恋爱情侣或者父母/孩子之间用的,可能还有另外几种场合,但十指相扣只属于认真交往的情侣。我终于鼓起勇气问 Femi 这是怎么回事,他告诉我朋友之间这么做非常正常。后来他弟弟也对我这么干了一次。这次我早有准备,直接接受了,因为管他呢,我人在尼日利亚,我们在手牵手,事情就这样。</p><p><strong>15) 打乒乓球其实只需要一个乒乓球就行。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/IMG_4621.jpg" target="_blank" rel="noreferrer"><img src="'+l+'" alt="Ping Pong"></a><br> (如果没看清楚——球拍是一块石头。)</p><p><strong>16) 如果哪天你有需要,你的车顶上最多可以塞 20 只鸡。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/IMG_4829.jpg" target="_blank" rel="noreferrer"><img src="'+m+'" alt="Chickens"></a></p><p><strong>17) 用一块布给这个婴儿的脸做个相框是一项好玩的活动。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/IMG_4793.jpg" target="_blank" rel="noreferrer"><img src="'+c+'" alt="Baby frame"></a></p><p><strong>18) 说到腐败和骗子横行,尼日利亚名声不好——而且是有充分理由的。</strong> 在它整个现代史上,尼日利亚一直都有腐败问题,而且从社会顶层贯穿到底层:</p><p>顶层</p><p>自 1960 年独立以来,几乎每一届当权政府——不管是四个共和国中的哪一个,还是军人独裁政权——都被指控腐败横行。哪怕在最近的 16 年里,也就是他们持续时间最长的文官民主时期,迄今为止最近的四次选举全都被广泛谴责涉嫌操纵选票。透明国际 (Transparency International) 2013 年的清廉指数 (Corruption Perception Index) 从最清廉到最腐败<a href="http://cpi.transparency.org/cpi2013/results/" target="_blank" rel="noreferrer">对各国进行排名</a>,把尼日利亚排在了 177 个国家中的第 144 位。</p><p>中层</p><p>应付低级政府官员的腐败——警察、保安、检查站官员——在尼日利亚是随处可见的日常生活。这部分我亲身体验过——大概 40 次。几乎每次坐车,我们都会被拦在检查站,然后走一遍同样的流程——警官会让我们摇下车窗,伸手进来跟我握手,然后笑着说些类似「那你今天给我带了什么啊?」的话。我会给他大约相当于 2 美元、4 美元或 5 美元的钱,然后我们就继续上路。当我们在某个著名地标停下来看看时,几个在那里工作或巡逻的人总会不可避免地走过来收钱。当我在一个热闹的露天市场时,我拍了张照,几秒钟后就有个人走过来对我施压,让我付「拍照费」,他说他是这个市场的负责人 (Femi 告诉我他基本上就是个黑帮的人)。我不知道如果我拒绝付钱,这些情况会怎么发展,但我决定不去弄清楚,除了这些小额付款之外也没发生什么坏事。</p><p>底层</p><p>每个上网的人都在某个时候遇到过尼日利亚骗局。有些是公然打着尼日利亚旗号的——比如那封臭名昭著的「一位尼日利亚王子刚刚去世,我们需要把他的财产送到海外的安全避风港,如果你同意接受这笔款项,你将因此获得 430 万美元的报酬,这一切都完全合情合理我保证」的邮件。有些是从尼日利亚运营的,但没有特别提到这个国家——比如回复你 Craigslist 卖沙发广告的邮件,用听起来怪怪的英文提议正好按你要的价格付款(骗局是他们「不小心」多付给你很多钱,然后让你把多出来的部分电汇回给他们——他们发给你的钱看起来确实在你账户里,所以你就把多出来的部分汇回去。然后几周后,银行发现那是一张假支票,你就得为全部金额负责……但你电汇出去的那笔「多余」的钱是真钱,骗子已经拿走并消失了)。</p><p>我来到尼日利亚时,特别想多了解一下搞这些骗局的人,于是问了一堆问题。原来,尼日利亚人管这些骗子叫「Yahoos」(读作「ya-OOZE」),因为他们以前一直用 Yahoo 来实施诈骗——那时候 Yahoo 还是人类会用的东西。据说他们现在不怎么骗美国人了,因为美国人不太上当了——他们转而盯上了丹麦和挪威,在这两个地方现在混得风生水起。我听说眼下有个热门骗术:先说服某个可怜寂寞的丹麦男人,让他相信你是个漂亮的美国姑娘(方法是伪造一个 Facebook 账号,再从别人的 Facebook 上偷些照片),花几个月时间和他建立关系,然后请这个男人寄机票钱,好让你去看他。他寄了,然后你就人间蒸发。他们甚至有一种机器,能把男人的声音变成女人的声音,用来在电话里跟对方聊天。多么诚实的好工作。</p><p>有一次,Femi 的弟弟不小心跟我提到,他跟一个 Yahoo 一起踢足球。一想到有机会见到一个活生生的 Yahoo,我就来劲了,漫不经心地把这事提了大概 25 遍,他终于同意介绍我认识(前提是我答应见面时无论如何都不提诈骗的事)。我们去了那个 Yahoo 家,虽然我没进屋,但那个 Yahoo 和他的三个 Yahoo 朋友出来到人行道上,跟我们聊了几分钟,然后就无聊了回屋去了。我像个疯子一样偷偷拍了照,现在我猜我要把它们发到网上?</p><p>那么请看——真实生活中 Yahoo 们的身影!(我真的不想给他们的脸打码,但我不能冒险让这些家伙被抓到,然后对 Femi 的弟弟报复。)</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/Yahoos.jpg" target="_blank" rel="noreferrer"><img src="'+_+'" alt="Yahoos"></a></p><p>就是这些家伙在给你发关于尼日利亚王子的邮件。Femi 告诉我,他们自从开始行骗以来已经变得非常有钱——但同时也承担着巨大的风险。警察在到处找 Yahoos,年轻人经常在检查站被拦下检查笔记本电脑。如果被抓到,他们会被判 20 到 30 年监禁。</p><p>他还说,Yahoos 被社会上大多数人所鄙视,这也凸显了一个让人难过的事实:大多数尼日利亚人都是诚实本分的人,他们只能被迫和这些下三滥的破事共存,更别提因此被玷污了名声——全世界的人都对和尼日利亚人做生意心存戒备。</p><p>那么我们复习一下,到目前为止本文我们已经了解到:尼日利亚人正在忍受无孔不入的腐败、政局动荡的过山车、阶层严重不平等、宗教暴力、严峻的健康问题以及压得人喘不过气的贫困。这就让接下来这件事显得非常令人惊讶——</p><p><strong>19) 世界价值观调查 (World Values Survey) 的一项<a href="http://news.bbc.co.uk/2/hi/africa/3157570.stm" target="_blank" rel="noreferrer">研究</a>发现,尼日利亚是全世界最幸福的国家。</strong></p><p>啊?</p><p>首先,我查了一下世界价值观调查是不是靠谱的机构——是的。然后我开始读为什么会这样,同时结合我在当地时自己的观察去琢磨。以下是两种解释:</p><p><strong>1) 尼日利亚人超级虔诚</strong>。伊斯兰教在尼日利亚北部的生活中已经扮演了几个世纪的重要角色。尼日利亚的基督徒直到 1970 年代之前大多是温和的天主教徒,但 80、90 年代由残酷的军事独裁统治国家,生活非常艰难,基督教传教士便乘机在全国点燃了一场声势浩大的福音派运动,这场运动至今仍是文化中极重要的一部分。宗教信仰似乎是一个「日子过得很惨但同时又超级幸福」的国家必不可少的成分。</p><p><strong>2) 尼日利亚人的乐观程度不同寻常</strong>。这不只是我的观察。盖洛普 <a href="https://www.theguardian.com/global/2011/jan/04/nigerians-top-optimism-poll" target="_blank" rel="noreferrer">2010</a> 年和 <a href="http://af.reuters.com/article/commoditiesNews/idAFL6E7NM2W520111223" target="_blank" rel="noreferrer">2011</a> 年连续两年的民调都发现尼日利亚是世界上最乐观的国家。心理学早就把乐观<a href="http://www.nasponline.org/publications/cq/pdf/v38n7_ft_optimism.pdf" target="_blank" rel="noreferrer">与幸福感联系起来</a>,尼日利亚人倾向于相信,虽然眼下可能不好,但一切正在好起来。我的亲身经历印证了这一点——Femi 家族里我认识的每一个人都有远大的抱负,并对未来充满兴奋。</p><p>尼日利亚人格外幸福,又一次证明了:幸福完全取决于你的心态,而跟你周围的外部世界一点关系都没有。</p><p>下面是尼日利亚的视频。我看到的、做过的一切,浓缩成 288 秒:</p><p>再放几张村子里的照片,因为我实在忍不住:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/IMG_4698.jpg" target="_blank" rel="noreferrer"><img src="'+w+'" alt="IMG4698"></a><br><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/IMG_4754.jpg" target="_blank" rel="noreferrer"><img src="'+u+'" alt="IMG4754"></a><br><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/IMG_4738.jpg" target="_blank" rel="noreferrer"><img src="'+f+'" alt="IMG4738"></a><br><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/IMG_4727.jpg" target="_blank" rel="noreferrer"><img src="'+b+'" alt="IMG4727"></a><br><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/IMG_4709.jpg" target="_blank" rel="noreferrer"><img src="'+d+'" alt="IMG4709"></a><br><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/IMG_4684.jpg" target="_blank" rel="noreferrer"><img src="'+k+'" alt="IMG4684"></a><br><a href="https://waitbutwhy.com/wp-content/uploads/2014/08/IMG_4700.jpg" target="_blank" rel="noreferrer"><img src="'+y+'" alt="IMG4700"></a></p><p><strong>其他站点:</strong><a href="https://waitbutwhy.com/2014/07/russia-what-you-didnt-know.html" target="_blank" rel="noreferrer">俄罗斯</a><a href="https://waitbutwhy.com/2014/07/japan-and-how-i-failed-to-figure-it-out.html" target="_blank" rel="noreferrer">日本</a><a href="https://waitbutwhy.com/2014/09/muhammad-isis-iraqs-full-story.html" target="_blank" rel="noreferrer">伊拉克</a><a href="https://waitbutwhy.com/2014/09/but-what-about-greenland.html" target="_blank" rel="noreferrer">格陵兰</a></p><p><a href="https://waitbutwhy.com/2014/09/genie-question.html" target="_blank" rel="noreferrer">我在五个国家都问过的那个神灯问题</a></p><h2 id="还有另一次去的朝鲜" tabindex="-1">还有另一次去的<a href="https://waitbutwhy.com/2013/09/20-things-i-learned-while-i-was-in.html" target="_blank" rel="noreferrer">朝鲜</a> <a class="header-anchor" href="#还有另一次去的朝鲜" aria-label="Permalink to &quot;还有另一次去的[朝鲜](https://waitbutwhy.com/2013/09/20-things-i-learned-while-i-was-in.html)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章发布时我们会发给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><hr><ol><li><p>当一个九岁男孩很惨。约翰 (John) 是 Femi 家的九岁小儿子。他是个特别棒的孩子——比同龄人成熟,总是笑呵呵的,而且非常聪明。他也是全世界的受气包。这当然不是尼日利亚特有的现象——全地球的九岁男孩都稳坐人类阶梯的最底层。九岁男孩已经过了能享受小孩特殊待遇的年纪,又还没到能对任何人摆资历的年纪,而且人们更愿意让这个年纪的男孩去干那些不愉快的体力活,而不是让女孩去。约翰的生活就是活生生的例子。只要哪里有点低级体力活,就会有人吼着让约翰去干。而他就默默承受所有人的破事,因为一个九岁男孩就只能这样。<a href="#note-1-2244">↩</a></p></li><li><p>这可不好受。车不动的时候我们的空调就不工作,所以我这四个小时都在吸周围车辆排出的浓烈尾气。除此之外,司机把音乐开得让人心烦意乱地大声,而且每当前面出现 10 英尺空隙就猛踩油门加速然后又猛踩刹车,晕得我想吐,而我这一路都在玩一个气死人不偿命的 Candy Crush 关卡怎么都过不去 (181 关)。不是这趟旅程的高光时刻。<a href="#note-2-2244">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/08/19-things-learned-nigeria.html&amp;description=19%20Things%20I%20Learned%20in%20Nigeria" target="_blank" rel="noreferrer"><img src="'+I+'" alt=""></a></p>',99)])])}const P=t(G,[["render",M]]);export{Y as __pageData,P as default};
